#!/bin/bash

## Generated by ChatGPT
## Download and extract Chrome extensions from a list of extension IDs

EXT_IDS_FILE="wallet-extensions.txt"
CHROME_VERSION="137.0.0.0"
BASE_URL="https://clients2.google.com/service/update2/crx"
OUTPUT_DIR="wallets_downloads"
EXTRACT_DIR="unzipped_extensions"
CSV_FILE="extension_report.csv"

# Clean the output directories
rm -rf "$OUTPUT_DIR" "$EXTRACT_DIR" "$CSV_FILE"
mkdir -p "$OUTPUT_DIR" "$EXTRACT_DIR"


# Write CSV header
echo "ID,Name,Valid" > "$CSV_FILE"


# Compute total
total=$(grep -Ev '^\s*($|#)' "$EXT_IDS_FILE" | wc -l)
index=0

# # Counters
# total=0
# success_downloads=0
# success_extracts=0

while read -r EXT_ID; do
    EXT_ID=$(echo "$EXT_ID" | tr -d '[:space:]')  # Trim whitespace
    [[ -z "$EXT_ID" || "$EXT_ID" =~ ^# ]] && continue
    index=$((index + 1))

    # echo "Downloading $EXT_ID ..."
    prefix=$(printf "[%3d/%3d]" "$index" "$total")
    echo "$prefix Downloading  $EXT_ID …"
    
    ZIP_PATH="${OUTPUT_DIR}/${EXT_ID}.zip"
    unzip_dir="${EXTRACT_DIR}/${EXT_ID}"

    # Attempt download
    if wget -q "${BASE_URL}?response=redirect&prodversion=${CHROME_VERSION}&x=id%3D${EXT_ID}%26installsource%3Dondemand%26uc&acceptformat=crx2,crx3" -O "$ZIP_PATH"; then
        ((success_downloads++))
        echo "$prefix Downloaded   $EXT_ID"
        echo "$prefix Extracting   $EXT_ID …"
        mkdir -p "$unzip_dir"

        if tar -xf "$ZIP_PATH" -C "$unzip_dir"; then
            ((success_extracts++))

            # Try to get the extension name from manifest
            MANIFEST="${unzip_dir}/manifest.json"
            if [ -f "$MANIFEST" ]; then
                NAME=$(jq -r '.name' "$MANIFEST" 2>/dev/null)
                NAME=${NAME:-Unknown}
            else
                NAME="Unknown"
            fi
            echo "$prefix Extracted    $EXT_ID — OK ✅"
            echo "$EXT_ID,\"$NAME\",yes" >> "$CSV_FILE"

        else
            echo "$EXT_ID,Unknown,no" >> "$CSV_FILE"
            echo "$prefix Extraction   $EXT_ID — FAILED ❌"
        fi
    else
        echo "$prefix Download     $EXT_ID — FAILED"
        echo "$EXT_ID,Unknown,no" >> "$CSV_FILE"
    fi

done < "$EXT_IDS_FILE"

# Summary
echo
echo "✅ Report: $CSV_FILE"
echo "   Downloads:   $OUTPUT_DIR"
echo "   Unpacked:    $EXTRACT_DIR"